1	//! Off-hot-path analysis: bucket iteration, quantiles, merge.
2	//!
3	//! - Shared by the borrowed and owned histogram types; all
4	//!   O(buckets), `no_std`, integer math except the quantile
5	//!   input itself.
6	//! - The iterator carries **cumulative** counts so band
7	//!   tables (quantile fences, trimmed stats) fall out of one
8	//!   pass — the readout requirement in ARCHITECTURE.md.
9	
10	use crate::config::{Config, Error};
11	use crate::counter::Counter;
12	
13	/// One bucket as seen by the iterator.
14	///
15	/// - `low`/`high` — inclusive value range.
16	/// - `count` — occurrences recorded in this bucket.
17	/// - `cumulative` — occurrences in this bucket and every
18	///   bucket below it (saturating).
19	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
20	pub struct Bucket {
21	    /// Inclusive low end of the bucket's value range.
22	    pub low: u64,
23	    /// Inclusive high end of the bucket's value range.
24	    pub high: u64,
25	    /// Count recorded in this bucket.
26	    pub count: u64,
27	    /// Saturating running total through this bucket.
28	    pub cumulative: u64,
29	}
30	
31	/// Iterator over every bucket (empty ones included), lowest
32	/// value first.
33	#[derive(Debug)]
34	pub struct Buckets<'a, C: Counter> {
35	    config: Config,
36	    counts: &'a [C],
37	    index: usize,
38	    cumulative: u64,
39	}
40	
41	impl<'a, C: Counter> Buckets<'a, C> {
42	    /// Build the iterator; internal (reached via the
43	    /// histogram types' `buckets()`).
44	    pub(crate) fn new(config: Config, counts: &'a [C]) -> Self {
45	        Buckets {
46	            config,
47	            counts,
48	            index: 0,
49	            cumulative: 0,
50	        }
51	    }
52	}
53	
54	impl<C: Counter> Iterator for Buckets<'_, C> {
55	    type Item = Bucket;
56	
57	    fn next(&mut self) -> Option<Bucket> {
58	        let c = self.counts.get(self.index)?;
59	        let count = c.to_u64();
60	        self.cumulative = self.cumulative.saturating_add(count);
61	        let (low, high) = self.config.value_range(self.index);
62	        self.index += 1;
63	        Some(Bucket {
64	            low,
65	            high,
66	            count,
67	            cumulative: self.cumulative,
68	        })
69	    }
70	
71	    fn size_hint(&self) -> (usize, Option<usize>) {
72	        let rest = self.counts.len() - self.index;
73	        (rest, Some(rest))
74	    }
75	}
76	
77	impl<C: Counter> ExactSizeIterator for Buckets<'_, C> {}
78	
79	/// Value at quantile `q` in `[0.0, 1.0]`: the **upper bound**
80	/// of the bucket holding the rank-`ceil(q·total)` recorded
81	/// value (matching hdrhistogram's highest-equivalent
82	/// convention; one-sided error ≤ 2⁻ᵍ).
83	///
84	/// `None` when the histogram is empty or `q` is outside
85	/// `[0.0, 1.0]` (NaN included). No `std` float intrinsics:
86	/// the ceil is done by integer compare. O(buckets), two
87	/// passes: `total` is summed from the counts first (nothing
88	/// tracks it on the record path).
89	pub(crate) fn quantile_of<C: Counter>(config: &Config, counts: &[C], q: f64) -> Option<u64> {
90	    let total = crate::histogram::total_of(counts);
91	    if total == 0 || !(0.0..=1.0).contains(&q) {
92	        return None;
93	    }
94	    // rank = clamp(ceil(q * total), 1, total) without f64::ceil.
95	    let rank_f = q * (total as f64);
96	    let mut rank = rank_f as u64;
97	    if (rank as f64) < rank_f {
98	        rank += 1;
99	    }
100	    let rank = rank.clamp(1, total);
101	
102	    let mut cumulative = 0u64;
103	    for (i, c) in counts.iter().enumerate() {
104	        cumulative = cumulative.saturating_add(c.to_u64());
105	        if cumulative >= rank {
106	            let (_, high) = config.value_range(i);
107	            return Some(high);
108	        }
109	    }
110	    // Unreachable: `total` is summed from these same counts,
111	    // so some bucket reaches `rank ≤ total`; fall back to the
112	    // top bucket rather than panic.
113	    let (_, high) = config.value_range(counts.len() - 1);
114	    Some(high)
115	}
116	
117	/// Merge `src` counts into `dst` (saturating), configs must
118	/// match.
119	pub(crate) fn merge_into<C: Counter>(
120	    dst_config: &Config,
121	    dst_counts: &mut [C],
122	    src_config: &Config,
123	    src_counts: &[C],
124	) -> Result<(), Error> {
125	    if dst_config != src_config {
126	        return Err(Error::ConfigMismatch);
127	    }
128	    for (d, s) in dst_counts.iter_mut().zip(src_counts.iter()) {
129	        *d = d.sat_add(s.to_u64());
130	    }
131	    Ok(())
132	}
133	
134	#[cfg(test)]
135	#[allow(clippy::unwrap_used)] // OK: tests panic on setup failure by design
136	mod tests {
137	    use crate::{Config, Error, Histogram, HistogramArray};
138	
139	    /// 1..=100 recorded once each in an exact-region config:
140	    /// quantiles are exact order statistics.
141	    #[test]
142	    fn quantile_exact_region() {
143	        let c = Config::new(7, 20).unwrap();
144	        let mut counts = [0u32; 1792];
145	        let mut h = Histogram::new(c, &mut counts).unwrap();
146	        for v in 1..=100u64 {
147	            h.record(v);
148	        }
149	        assert_eq!(h.quantile(0.0), Some(1));
150	        assert_eq!(h.quantile(0.5), Some(50));
151	        assert_eq!(h.quantile(0.90), Some(90));
152	        assert_eq!(h.quantile(1.0), Some(100));
153	    }
154	
155	    #[test]
156	    fn quantile_edge_cases() {
157	        let c = Config::new(2, 8).unwrap();
158	        let mut counts = [0u32; 28];
159	        let mut h = Histogram::new(c, &mut counts).unwrap();
160	        assert_eq!(h.quantile(0.5), None); // empty
161	        h.record(10);
162	        assert_eq!(h.quantile(-0.1), None);
163	        assert_eq!(h.quantile(1.1), None);
164	        assert_eq!(h.quantile(f64::NAN), None);
165	    }
166	
167	    /// In the log region the quantile is the bucket's upper
168	    /// bound containing the ranked value.
169	    #[test]
170	    fn quantile_upper_bound_convention() {
171	        let c = Config::new(2, 10).unwrap();
172	        let mut counts = [0u32; 36];
173	        let mut h = Histogram::new(c, &mut counts).unwrap();
174	        h.record(1000); // single value, above exact region
175	        let idx = c.index_for(1000);
176	        let (low, high) = c.value_range(idx);
177	        assert!(low <= 1000 && 1000 <= high);
178	        assert_eq!(h.quantile(0.5), Some(high));
179	    }
180	
181	    #[test]
182	    fn buckets_cumulative_and_partition() {
183	        let c = Config::new(2, 8).unwrap();
184	        let mut counts = [0u32; 28];
185	        let mut h = Histogram::new(c, &mut counts).unwrap();
186	        for v in [0u64, 3, 3, 9, 100, 255] {
187	            h.record(v);
188	        }
189	        let buckets: std::vec::Vec<crate::Bucket> = h.buckets().collect();
190	        assert_eq!(buckets.len(), c.total_buckets());
