90	    /// value pays one compare and no clamp; over-max values
91	    /// are always ≥ `2^(g+1)` (g < n), so clamping only on
92	    /// the log path is equivalent.
93	    #[inline]
94	    pub const fn index_for(&self, value: u64) -> usize {
95	        if value < (1u64 << (self.grouping_power + 1)) {
96	            return value as usize;
97	        }
98	        let v = if value > self.max_value() {
99	            self.max_value()
100	        } else {
101	            value
102	        };
103	        let power = 63 - v.leading_zeros() as u8;
104	        let log_bucket = power - self.grouping_power;
105	        ((log_bucket as usize) << self.grouping_power)
106	            + ((v >> (power - self.grouping_power)) as usize)
107	    }
