mod tests {
    use super::*;

    #[test]
    fn size_checked() {
        let c = Config::new(2, 8).unwrap(); // 28 buckets
        assert!(matches!(
            HistogramArray::<27>::new(c),
            Err(Error::StorageLen)
        ));
        assert!(HistogramArray::<28>::new(c).is_ok());
