1	//! Record-path cost bench (hand-rolled, `harness = false`).
2	//!
3	//! - Times ns/record over a pre-generated heavy-tailed value
4	//!   stream; best of `REPS` passes per variant. The variant
5	//!   list, how to interpret each row, and the caveats are
6	//!   documented in README.md's Bench section.
7	//! - Purpose: absolute record cost vs a raw store, the
8	//!   iopsystems `histogram` crate (same h2 scheme), and
9	//!   `hdrhistogram`; plus diagnostic rows isolating the
10	//!   marginal cost of a hot-path total and the min/max/sum
11	//!   extras — the data behind those design decisions.
12	
13	use std::hint::black_box;
14	use std::time::Instant;
15	
16	use h2hist::{Config, Error, Histogram};
17	
18	/// Samples per pass.
19	const LEN: usize = 8_000_000;
20	/// Timed passes per variant; best is reported.
21	const REPS: usize = 3;
22	
23	/// Deterministic 64-bit PRNG (splitmix64); same shape as the
24	/// oracle suite.
25	struct SplitMix64(u64);
26	
27	impl SplitMix64 {
28	    /// Next raw u64.
