    let count_w = rows.iter().map(|r| r.count.len()).max().unwrap_or(0);
    let mean_w = rows
        .iter()
        .map(|r| r.mean.len())
        .chain([hist_mean_s.len(), hist_stdev_s.len()])
        .chain(trim.iter().flat_map(|(m, _, s)| [m.len(), s.len()]))
        .chain(
